import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { User, LogOut, LayoutDashboard, UserPlus } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

const Header = () => {
  const navigate = useNavigate();
  const { user, isAuthenticated, logout } = useAuth();
  
  // Obtenemos el nombre directamente del contexto
  const nombreUsuario = user?.nombre || "Usuario";

  return (
    <header style={headerContainer}>
      {/* LOGO */}
      <div style={logoSection} onClick={() => navigate('/')}>
        <span style={logoWhite}>OFERTAS</span>
        <span style={logoOrange}>APP</span>
      </div>

      <nav style={navLinks}>
        {!isAuthenticated ? (
          /* --- ESTADO: NO LOGUEADO --- */
          <>
            <Link to="/registro" style={linkWhite}>
              <UserPlus size={18} /> 
              <span>Crear una cuenta</span>
            </Link>
            <Link to="/login" style={loginButton}>Ingresar</Link>
          </>
        ) : (
          /* --- ESTADO: LOGUEADO --- */
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            
            {/* Mensaje de Bienvenida */}
            <div style={userInfo}>
              <User size={16} color="#94a3b8" />
              <span style={{ color: 'white', fontSize: '0.9rem' }}>
                Hola, <strong style={{ color: '#e67e22' }}>{nombreUsuario}</strong>
              </span>
            </div>

            {/* BOTÓN DINÁMICO SEGÚN ROL */}
            <button 
              onClick={() => navigate(user?.rol === 'vendedor' ? '/dashboard' : '/panel-cliente')} 
              style={panelButton}
            >
              <LayoutDashboard size={18} />
              <span>{user?.rol === 'vendedor' ? 'Mi Comercio' : 'Ver Ofertas'}</span>
            </button>
            
            {/* BOTÓN CERRAR SESIÓN */}
            <button 
              onClick={() => {
                logout();
                navigate('/login');
              }} 
              style={logoutBtn}
              title="Cerrar Sesión"
            >
              <LogOut size={20} />
            </button>
          </div>
        )}
      </nav>
    </header>
  );
};

// --- ESTILOS ---
const headerContainer = { 
  display: 'flex', 
  justifyContent: 'space-between', 
  alignItems: 'center', 
  padding: '0 5%', 
  background: '#1e293b', 
  height: '75px', 
  position: 'sticky', 
  top: 0, 
  zIndex: 1000,
  boxShadow: '0 4px 10px rgba(0,0,0,0.1)'
};

const logoSection = { cursor: 'pointer', fontSize: '1.6rem', fontWeight: '800', letterSpacing: '-1px' };
const logoWhite = { color: '#ffffff' };
const logoOrange = { color: '#e67e22', marginLeft: '2px' };
const navLinks = { display: 'flex', alignItems: 'center', gap: '25px' };
const linkWhite = { color: '#cbd5e1', textDecoration: 'none', fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '8px' };
const loginButton = { background: '#e67e22', color: 'white', padding: '10px 22px', borderRadius: '10px', textDecoration: 'none', fontWeight: 'bold', fontSize: '0.9rem' };
const userInfo = { display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(255,255,255,0.05)', padding: '6px 12px', borderRadius: '8px' };
const panelButton = { background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22', padding: '8px 18px', borderRadius: '10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const logoutBtn = { background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '5px' };

export default Header;
